Patch Set 3:

I realized the codes that I was thinking of could cause unncessary OBP(statfs), which is exactly the problem that this patch is trying to fix. So, maybe something like following is better:

if (obd->obd_osfs_age < max_age ...) {
    rc = mutex_lock_interruptible(&obd->obd_dev_mutex);
    if (rc)
        RETURN(rc);
    if (obd->obd_osfs_age < max_age ...) {
        rc = OBP(...)
        if (rc) {
            mutex_unlock(&obd->obd_dev_mutex);
            RETURN(rc);
        }
        spin_lock(&obd->obd_osfs_lock);
        obd->obd_osfs_age = ktime_get_seconds();
        spin_unlock(&obd->obd_osfs_lock);
    }
    mutex_unlock(&obd->obd_dev_mutex);
    if (rc)
        RETURN(rc);
}

spin_lock(&obd->obd_osfs_lock);
memcpy(osfs, &obd->obd_osfs, sizeof(*osfs));
spin_unlock(&obd->obd_osfs_lock);
RETURN(0);

I am not sure whether getting obd_osfs_lock twice would cause any problem (performance impact?). Seems OK.
